struct VulkanResidentPendingPrivateFeedback {
    token_id: u32,
    feedback_depth: u32,
    closes_loop_after_processing: bool,
}

#[derive(Debug)]
pub enum VulkanResidentFeedbackLoopRunnerError {
    ZeroTickBudget,
    EmptyPromptEvent,
    MissingPrivateFeedback,
    StreamTickOverflow,
    DynamicStateCapacityOverflow,
    OutputBudgetOverflow,
    FeedbackDepthOverflow,
    DispatchCountOverflow,
    DescriptorCountOverflow,
    PushConstantByteCountOverflow,
    FeedbackCycleWidthExceeded {
        requested: usize,
        snapshot_capacity: usize,
        sampler_history_capacity: usize,
    },
    FeedbackCyclePushConstants {
        byte_count: u32,
    },
    Tick(VulkanResidentSingleTokenTickRunnerError),
    Sampler(VulkanResidentSamplerRunnerError),
    Vulkan(VulkanError),
}

impl Display for VulkanResidentFeedbackLoopRunnerError {
    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::ZeroTickBudget => f.write_str("feedback loop tick budget must not be zero"),
            Self::EmptyPromptEvent => f.write_str("prompt event must contain input"),
            Self::MissingPrivateFeedback => f.write_str("prompt event expected private feedback"),
            Self::StreamTickOverflow => f.write_str("feedback loop stream tick overflowed"),
            Self::DynamicStateCapacityOverflow => {
                f.write_str("feedback loop dynamic state capacity overflowed")
            }
            Self::OutputBudgetOverflow => f.write_str("running stream output budget overflowed"),
            Self::FeedbackDepthOverflow => f.write_str("feedback loop feedback depth overflowed"),
            Self::DispatchCountOverflow => f.write_str("feedback loop dispatch count overflowed"),
            Self::DescriptorCountOverflow => {
                f.write_str("feedback loop descriptor count overflowed")
            }
            Self::PushConstantByteCountOverflow => {
                f.write_str("feedback loop push constant byte count overflowed")
            }
            Self::FeedbackCycleWidthExceeded {
                requested,
                snapshot_capacity,
                sampler_history_capacity,
            } => write!(
                f,
                "resident feedback cycle requests {requested} ticks, snapshot capacity is {snapshot_capacity} and sampler history capacity is {sampler_history_capacity}"
            ),
            Self::FeedbackCyclePushConstants { byte_count } => write!(
                f,
                "resident feedback cycle requires buffer-backed control, but the compiled tick ABI still declares {byte_count} push-constant bytes"
            ),
            Self::Tick(error) => Display::fmt(error, f),
            Self::Sampler(error) => Display::fmt(error, f),
            Self::Vulkan(error) => Display::fmt(error, f),
        }
    }
}

impl Error for VulkanResidentFeedbackLoopRunnerError {}

impl From<VulkanResidentSingleTokenTickRunnerError> for VulkanResidentFeedbackLoopRunnerError {
    fn from(error: VulkanResidentSingleTokenTickRunnerError) -> Self {
        Self::Tick(error)
    }
}

impl From<VulkanResidentSamplerRunnerError> for VulkanResidentFeedbackLoopRunnerError {
    fn from(error: VulkanResidentSamplerRunnerError) -> Self {
        Self::Sampler(error)
    }
}

impl From<VulkanError> for VulkanResidentFeedbackLoopRunnerError {
    fn from(error: VulkanError) -> Self {
        Self::Vulkan(error)
    }
}

struct VulkanResidentStaticStateSnapshotEntry {
    state_buffer_index: usize,
    byte_capacity: usize,
    snapshots: VulkanResidentBuffer,
}

struct VulkanResidentStaticStateSnapshotBank {
    cycle_width: usize,
    entries: Vec<VulkanResidentStaticStateSnapshotEntry>,
}

impl VulkanResidentStaticStateSnapshotBank {
    fn new(
        device: &VulkanComputeDevice,
        buffers: &VulkanStreamCircuitStreamBuffers,
        cycle_width: usize,
    ) -> Result<Self, VulkanError> {
        if cycle_width == 0 {
            return Err(VulkanError(
                "resident feedback snapshot cycle width must not be zero".to_string(),
            ));
        }
        let mut entries = Vec::new();
        for (state_buffer_index, state) in buffers.state_buffers.iter().enumerate() {
            if state.static_byte_capacity.is_none() {
                continue;
            }
            let snapshot_byte_capacity =
                state
                    .byte_capacity
                    .checked_mul(cycle_width)
                    .ok_or_else(|| {
                        VulkanError("resident feedback snapshot capacity overflowed".to_string())
                    })?;
            let mut snapshots =
                device.create_host_visible_resident_buffer(snapshot_byte_capacity)?;
            snapshots.persistently_map()?;
            entries.push(VulkanResidentStaticStateSnapshotEntry {
                state_buffer_index,
                byte_capacity: state.byte_capacity,
                snapshots,
            });
        }
        Ok(Self {
            cycle_width,
            entries,
        })
    }

    fn copies_for_cycle<'a>(
        &'a self,
        buffers: &'a VulkanStreamCircuitStreamBuffers,
        steps_per_tick: usize,
        tick_count: usize,
    ) -> Result<Vec<VulkanResidentKernelSequenceSnapshotCopy<'a>>, VulkanError> {
        if tick_count == 0 || tick_count > self.cycle_width {
            return Err(VulkanError(format!(
                "resident feedback snapshot cycle contains {tick_count} ticks, capacity is {}",
                self.cycle_width
            )));
        }
        let mut copies = Vec::with_capacity(self.entries.len() * tick_count);
        for tick_index in 0..tick_count {
            let after_step_index = (tick_index + 1)
                .checked_mul(steps_per_tick)
                .and_then(|step| step.checked_sub(1))
                .ok_or_else(|| {
                    VulkanError("resident feedback snapshot step index overflowed".to_string())
                })?;
            for entry in &self.entries {
                let state = &buffers.state_buffers[entry.state_buffer_index];
                copies.push(VulkanResidentKernelSequenceSnapshotCopy::new(
                    after_step_index,
                    &state.buffer,
                    &entry.snapshots,
                    0,
                    tick_index * entry.byte_capacity,
                    entry.byte_capacity,
                )?);
            }
        }
        Ok(copies)
    }

    fn restore_after_tick(
        &self,
        buffers: &VulkanStreamCircuitStreamBuffers,
        tick_index: usize,
    ) -> Result<(), VulkanError> {
        if tick_index >= self.cycle_width {
            return Err(VulkanError(format!(
                "resident feedback snapshot tick {tick_index} exceeds capacity {}",
                self.cycle_width
            )));
        }
        for entry in &self.entries {
            let offset = tick_index * entry.byte_capacity;
            let bytes = entry.snapshots.read_bytes_at(offset, entry.byte_capacity)?;
            buffers.state_buffers[entry.state_buffer_index]
                .buffer
                .write_bytes(&bytes)?;
        }
        Ok(())
    }
}

pub struct VulkanResidentStreamProcessor {
    pub device_id: String,
    pub pedal_count: usize,
    pub per_tick_dispatch_count: usize,
    pub per_tick_descriptor_count: usize,
    pub per_tick_push_constant_byte_count: u32,
    pub dynamic_state_capacity_activations: usize,
    _mounted: VulkanMountedPlacedStreamCircuit,
    _transducer_parameter_buffers: Arc<VulkanPermanentParameterBuffers>,
    loop_runner: VulkanResidentFeedbackLoopRunner,
    static_state_snapshots: VulkanResidentStaticStateSnapshotBank,
    backend_loop_window: usize,
}

impl VulkanResidentStreamProcessor {
    pub fn new(
        device: &VulkanComputeDevice,
        mounted: VulkanMountedPlacedStreamCircuit,
        transducer_parameter_buffers: Arc<VulkanPermanentParameterBuffers>,
        loop_runner: VulkanResidentFeedbackLoopRunner,
    ) -> Result<Self, VulkanError> {
        let backend_loop_window = backend_loop_window_for_static_state_bytes(
            mounted
                .buffers
                .state_buffers
                .iter()
                .filter_map(|state| state.static_byte_capacity)
                .try_fold(0usize, |total, bytes| total.checked_add(bytes))
                .ok_or_else(|| VulkanError("static state snapshot size overflowed".to_string()))?,
            loop_runner.sampler.history_capacity_activations,
        );
        let static_state_snapshots = VulkanResidentStaticStateSnapshotBank::new(
            device,
            &mounted.buffers,
            backend_loop_window,
        )?;
        Ok(Self {
            device_id: loop_runner.device_id.clone(),
            pedal_count: loop_runner.pedal_count,
            per_tick_dispatch_count: loop_runner.per_tick_dispatch_count,
            per_tick_descriptor_count: loop_runner.per_tick_descriptor_count,
            per_tick_push_constant_byte_count: loop_runner.per_tick_push_constant_byte_count,
            dynamic_state_capacity_activations: mounted.buffers.dynamic_state_capacity_activations,
            _mounted: mounted,
            _transducer_parameter_buffers: transducer_parameter_buffers,
            loop_runner,
            static_state_snapshots,
            backend_loop_window,
        })
    }

    pub fn run_bounded(
        &self,
        device: &VulkanComputeDevice,
        initial_token_id: u32,
        start_stream_tick: u64,
        max_ticks: usize,
    ) -> Result<VulkanResidentFeedbackLoopRun, VulkanResidentFeedbackLoopRunnerError> {
        self.loop_runner.run_bounded(
            device,
            initial_token_id,
            start_stream_tick,
            self.dynamic_state_capacity_activations_u32()?,
            max_ticks,
        )
    }

    pub fn run_prompt_event_bounded(
        &self,
        device: &VulkanComputeDevice,
        prompt_token_ids: &[u32],
        start_stream_tick: u64,
        max_new_tokens: usize,
        eos_token_id: Option<u32>,
    ) -> Result<VulkanResidentPromptEventRun, VulkanResidentFeedbackLoopRunnerError> {
        self.loop_runner.run_prompt_event_bounded(
            device,
            prompt_token_ids,
            start_stream_tick,
            self.dynamic_state_capacity_activations_u32()?,
            max_new_tokens,
            eos_token_id,
        )
    }

    fn dynamic_state_capacity_activations_u32(
        &self,
    ) -> Result<u32, VulkanResidentFeedbackLoopRunnerError> {
        u32::try_from(self.dynamic_state_capacity_activations)
            .map_err(|_| VulkanResidentFeedbackLoopRunnerError::DynamicStateCapacityOverflow)
    }

    pub fn into_running_stream(self, stream_id: impl Into<String>) -> VulkanResidentRunningStream {
        VulkanResidentRunningStream::new(stream_id, self)
    }

    pub fn into_token_stream(self, stream_id: impl Into<String>) -> VulkanResidentTokenStream {
        VulkanResidentTokenStream::new(stream_id, self)
    }

    pub fn backend_loop_window(&self) -> usize {
        self.backend_loop_window
    }
}

fn backend_loop_window_for_static_state_bytes(
    static_state_bytes: usize,
    sampler_history_capacity: usize,
) -> usize {
    let snapshot_limited = if static_state_bytes == 0 {
        VULKAN_BACKEND_LOOP_MAX_WINDOW
    } else {
        (VULKAN_BACKEND_LOOP_SNAPSHOT_BUDGET_BYTES / static_state_bytes).max(1)
    };
    VULKAN_BACKEND_LOOP_MAX_WINDOW
        .min(snapshot_limited)
        .min(sampler_history_capacity.max(1))
}

pub struct VulkanResidentRunningStream {
    pub stream_id: String,
    pub next_stream_tick: u64,
    pub remaining_public_outputs: usize,
    pub eos_token_id: Option<u32>,
    pub stop_token_ids: Vec<u32>,
    pub loop_open: bool,
    pub last_stop_reason: Option<String>,
    processor: VulkanResidentStreamProcessor,
    external_input_queue: VecDeque<VulkanResidentExternalInputSignal>,
    private_feedback_queue: VecDeque<VulkanResidentPrivateFeedbackSignal>,
    public_outputs: Vec<VulkanResidentPublicOutputSignal>,
    private_feedback_history: Vec<VulkanResidentPrivateFeedbackSignal>,
    ticks: Vec<VulkanResidentRunningStreamTick>,
    input_counter: usize,
    public_counter: usize,
    feedback_counter: usize,
}

impl VulkanResidentRunningStream {
    pub fn new(stream_id: impl Into<String>, processor: VulkanResidentStreamProcessor) -> Self {
        Self {
            stream_id: stream_id.into(),
            next_stream_tick: 0,
            remaining_public_outputs: 0,
            eos_token_id: None,
            stop_token_ids: Vec::new(),
            loop_open: false,
            last_stop_reason: None,
            processor,
            external_input_queue: VecDeque::new(),
            private_feedback_queue: VecDeque::new(),
            public_outputs: Vec::new(),
            private_feedback_history: Vec::new(),
            ticks: Vec::new(),
            input_counter: 0,
            public_counter: 0,
            feedback_counter: 0,
        }
    }

    pub fn inject_token(
        &mut self,
        token_id: u32,
        origin: impl Into<String>,
    ) -> VulkanResidentExternalInputSignal {
        let signal = VulkanResidentExternalInputSignal {
            id: format!("input_{}", self.input_counter),
            token_id,
            origin: origin.into(),
        };
        self.input_counter += 1;
        self.external_input_queue.push_back(signal.clone());
        signal
    }

    pub fn inject_prompt(
        &mut self,
        prompt_token_ids: &[u32],
        max_new_tokens: usize,
        eos_token_id: Option<u32>,
    ) -> Result<Vec<VulkanResidentExternalInputSignal>, VulkanResidentFeedbackLoopRunnerError> {
        self.inject_external_tokens(
            prompt_token_ids,
            max_new_tokens,
            eos_token_id,
            "external_input",
        )
    }

    pub fn inject_external_tokens(
        &mut self,
        token_ids: &[u32],
        max_new_tokens: usize,
        eos_token_id: Option<u32>,
        origin: impl Into<String>,
    ) -> Result<Vec<VulkanResidentExternalInputSignal>, VulkanResidentFeedbackLoopRunnerError> {
        self.inject_external_tokens_with_stop_tokens(
            token_ids,
            max_new_tokens,
            eos_token_id.into_iter().collect(),
            origin,
        )
    }

    pub fn inject_external_tokens_with_stop_tokens(
        &mut self,
        token_ids: &[u32],
        max_new_tokens: usize,
        stop_token_ids: Vec<u32>,
        origin: impl Into<String>,
    ) -> Result<Vec<VulkanResidentExternalInputSignal>, VulkanResidentFeedbackLoopRunnerError> {
        if token_ids.is_empty() {
            return Err(VulkanResidentFeedbackLoopRunnerError::EmptyPromptEvent);
        }
        let origin = origin.into();

        self.remaining_public_outputs =
            self.remaining_public_outputs
                .checked_add(max_new_tokens)
                .ok_or(VulkanResidentFeedbackLoopRunnerError::OutputBudgetOverflow)?;
        self.eos_token_id = stop_token_ids.first().copied();
        self.stop_token_ids = stop_token_ids;
        self.loop_open = self.remaining_public_outputs > 0;
        self.last_stop_reason = (max_new_tokens == 0).then(|| "max_new_tokens".to_string());

        Ok(token_ids
            .iter()
            .copied()
            .map(|token_id| self.inject_token(token_id, origin.clone()))
            .collect())
    }

    pub fn continue_loop(
        &mut self,
        additional_public_outputs: usize,
    ) -> Result<(), VulkanResidentFeedbackLoopRunnerError> {
        self.remaining_public_outputs = self
            .remaining_public_outputs
            .checked_add(additional_public_outputs)
            .ok_or(VulkanResidentFeedbackLoopRunnerError::OutputBudgetOverflow)?;
        if self.remaining_public_outputs > 0 {
            self.loop_open = true;
            self.last_stop_reason = None;
        }
        Ok(())
    }

    pub fn interrupt(&mut self, reason: impl Into<String>) -> VulkanResidentStreamControlEvent {
        let reason = reason.into();
        let cleared_private_feedback_ids = self
            .private_feedback_queue
            .iter()
            .map(|signal| signal.id.clone())
            .collect::<Vec<_>>();
        self.private_feedback_queue.clear();
        self.remaining_public_outputs = 0;
        self.loop_open = false;
        self.last_stop_reason = Some(reason.clone());

        VulkanResidentStreamControlEvent {
            event_type: VulkanResidentStreamControlEventType::Interrupt,
            reason,
            cleared_private_feedback_ids,
            closing_private_feedback_id: None,
            state_preserved: true,
        }
    }

    pub fn stop_after_current(
        &mut self,
        reason: impl Into<String>,
    ) -> VulkanResidentStreamControlEvent {
        let reason = reason.into();
        let mut cleared_private_feedback_ids = Vec::new();
        let mut closing_private_feedback_id = None;

        if let Some(mut current) = self.private_feedback_queue.pop_front() {
            closing_private_feedback_id = Some(current.id.clone());
            current.closes_loop_after_processing = true;
            current.stop_reason = Some(reason.clone());
            if let Some(history_signal) = self
                .private_feedback_history
                .iter_mut()
                .find(|signal| signal.id == current.id)
            {
                history_signal.closes_loop_after_processing = true;
                history_signal.stop_reason = Some(reason.clone());
            }
            cleared_private_feedback_ids.extend(
                self.private_feedback_queue
                    .drain(..)
                    .map(|signal| signal.id),
            );
            self.private_feedback_queue.push_front(current);
            self.loop_open = true;
        } else {
            self.loop_open = false;
        }

        self.remaining_public_outputs = 0;
        self.last_stop_reason = Some(reason.clone());

        VulkanResidentStreamControlEvent {
            event_type: VulkanResidentStreamControlEventType::StopAfterCurrent,
            reason,
            cleared_private_feedback_ids,
            closing_private_feedback_id,
            state_preserved: true,
        }
    }

    pub fn tick(
        &mut self,
        device: &VulkanComputeDevice,
    ) -> Result<VulkanResidentRunningStreamTick, VulkanResidentFeedbackLoopRunnerError> {
        if self.external_input_queue.is_empty() && self.private_feedback_queue.is_empty() {
            let tick = VulkanResidentRunningStreamTick {
                stream_id: self.stream_id.clone(),
                stream_tick: None,
                status: VulkanResidentRunningStreamTickStatus::Idle,
                input_signal: None,
                tick_run: None,
                public_output: None,
                private_feedback: None,
                sampler_run: None,
                stop_reason: self.last_stop_reason.clone(),
            };
            self.ticks.push(tick.clone());
            return Ok(tick);
        }

        let stream_tick = self.next_stream_tick;
        let input_signal = self
            .next_input_signal()
            .ok_or(VulkanResidentFeedbackLoopRunnerError::MissingPrivateFeedback)?;
        let should_emit_public_output =
            self.remaining_public_outputs > 0 && self.external_input_queue.is_empty();
        let tick_run = self
            .processor
            .loop_runner
            .tick_runner
            .run_token_id_with_stream_control_and_tail(
                device,
                input_signal.token_id(),
                VulkanMountedPlacedStreamControl {
                    stream_tick,
                    control_flags: 0,
                    dynamic_state_capacity_activations: self
                        .processor
                        .dynamic_state_capacity_activations_u32()?,
                },
                matches!(
                    &input_signal,
                    VulkanResidentRunningStreamInputSignal::PrivateFeedback(_)
                ),
                should_emit_public_output,
                should_emit_public_output
                    .then_some(&self.processor.loop_runner.sampler.resident_dispatch),
            )?;
        self.next_stream_tick = self
            .next_stream_tick
            .checked_add(1)
            .ok_or(VulkanResidentFeedbackLoopRunnerError::StreamTickOverflow)?;

        let mut public_output = None;
        let mut private_feedback = None;
        let mut sampler_run = None;

        if should_emit_public_output {
            let run = self.processor.loop_runner.sampler.completed_run()?;
            let sampled_token_id = run.token_id;
            self.remaining_public_outputs -= 1;

            let public = VulkanResidentPublicOutputSignal {
                id: format!("public_{}", self.public_counter),
                token_id: sampled_token_id,
                source_stream_tick: stream_tick,
                sampler_run: run.clone(),
            };
            self.public_counter += 1;
            self.public_outputs.push(public.clone());

            let close_after_feedback = if self.stop_token_ids.contains(&sampled_token_id) {
                self.remaining_public_outputs = 0;
                self.last_stop_reason = Some("eos".to_string());
                true
            } else if self.remaining_public_outputs == 0 {
                self.last_stop_reason = Some("max_new_tokens".to_string());
                true
            } else {
                false
            };
            let feedback_depth = input_signal
                .feedback_depth()
                .checked_add(1)
                .ok_or(VulkanResidentFeedbackLoopRunnerError::FeedbackDepthOverflow)?;
            let feedback = VulkanResidentPrivateFeedbackSignal {
                id: format!("feedback_{}", self.feedback_counter),
                token_id: sampled_token_id,
                source_public_output_id: public.id.clone(),
                feedback_depth,
                closes_loop_after_processing: close_after_feedback,
                stop_reason: self
                    .last_stop_reason
                    .clone()
                    .filter(|_| close_after_feedback),
            };
            self.feedback_counter += 1;
            self.private_feedback_queue.push_back(feedback.clone());
            self.private_feedback_history.push(feedback.clone());

            sampler_run = Some(run);
            public_output = Some(public);
            private_feedback = Some(feedback);
        }

        if input_signal.closes_loop_after_processing() {
            self.loop_open = false;
            self.last_stop_reason = input_signal
                .stop_reason()
                .cloned()
                .or_else(|| self.last_stop_reason.clone())
                .or_else(|| Some("max_new_tokens".to_string()));
        }

        let tick = VulkanResidentRunningStreamTick {
            stream_id: self.stream_id.clone(),
            stream_tick: Some(stream_tick),
            status: VulkanResidentRunningStreamTickStatus::Processed,
            input_signal: Some(input_signal),
            tick_run: Some(tick_run),
            public_output,
            private_feedback,
            sampler_run,
            stop_reason: self.last_stop_reason.clone(),
        };
        self.ticks.push(tick.clone());
        Ok(tick)
    }

    fn feedback_cycle_tick_count(&self, max_ticks: usize) -> usize {
        if max_ticks < 2
            || !self.external_input_queue.is_empty()
            || self.private_feedback_queue.len() != 1
            || self.remaining_public_outputs < 2
            || self
                .private_feedback_queue
                .front()
                .is_some_and(|feedback| feedback.closes_loop_after_processing)
        {
            return 0;
        }
        max_ticks
            .min(self.remaining_public_outputs)
            .min(self.processor.static_state_snapshots.cycle_width)
            .min(
                self.processor
                    .loop_runner
                    .sampler
                    .history_capacity_activations,
            )
    }

    fn drive_backend_loop_window(
        &mut self,
        device: &VulkanComputeDevice,
        max_ticks: usize,
    ) -> Result<Vec<VulkanResidentRunningStreamTick>, VulkanResidentFeedbackLoopRunnerError> {
        let tick_count = self.feedback_cycle_tick_count(max_ticks);
        if tick_count < 2 {
            return Ok(vec![self.tick(device)?]);
        }
        let initial_input = self
            .next_input_signal()
            .ok_or(VulkanResidentFeedbackLoopRunnerError::MissingPrivateFeedback)?;
        let initial_token_id = initial_input.token_id();
        let start_stream_tick = self.next_stream_tick;
        let cycle = self.processor.loop_runner.run_resident_feedback_cycle(
            device,
            initial_token_id,
            start_stream_tick,
            tick_count,
            &self.processor._mounted.buffers,
            &self.processor.static_state_snapshots,
        )?;

        let mut input_signal = Some(initial_input);
        let mut feedback_to_queue = None;
        let mut restore_after_tick = None;
        let mut ticks = Vec::with_capacity(tick_count);
        let cycle_tick_count = cycle.tick_runs.len();

        for (tick_index, cycle_tick) in cycle.tick_runs.into_iter().enumerate() {
            let input = input_signal
                .take()
                .ok_or(VulkanResidentFeedbackLoopRunnerError::MissingPrivateFeedback)?;
            self.next_stream_tick = self
                .next_stream_tick
                .checked_add(1)
                .ok_or(VulkanResidentFeedbackLoopRunnerError::StreamTickOverflow)?;

            if input.closes_loop_after_processing() {
                self.loop_open = false;
                self.last_stop_reason = input
                    .stop_reason()
                    .cloned()
                    .or_else(|| self.last_stop_reason.clone())
                    .or_else(|| Some("eos".to_string()));
                let tick = VulkanResidentRunningStreamTick {
                    stream_id: self.stream_id.clone(),
                    stream_tick: Some(cycle_tick.stream_tick),
                    status: VulkanResidentRunningStreamTickStatus::Processed,
                    input_signal: Some(input),
                    tick_run: Some(cycle_tick.tick_run),
                    public_output: None,
                    private_feedback: None,
                    sampler_run: None,
                    stop_reason: self.last_stop_reason.clone(),
                };
                self.ticks.push(tick.clone());
                ticks.push(tick);
                restore_after_tick = Some(tick_index);
                break;
            }

            let run = cycle_tick.sampler_run;
            let sampled_token_id = run.token_id;
            self.remaining_public_outputs -= 1;
            let public = VulkanResidentPublicOutputSignal {
                id: format!("public_{}", self.public_counter),
                token_id: sampled_token_id,
                source_stream_tick: cycle_tick.stream_tick,
                sampler_run: run.clone(),
            };
            self.public_counter += 1;
            self.public_outputs.push(public.clone());

            let sampled_eos = self.stop_token_ids.contains(&sampled_token_id);
            let close_after_feedback = if sampled_eos {
                self.remaining_public_outputs = 0;
                self.last_stop_reason = Some("eos".to_string());
                true
            } else if self.remaining_public_outputs == 0 {
                self.last_stop_reason = Some("max_new_tokens".to_string());
                true
            } else {
                false
            };
            let feedback_depth = input
                .feedback_depth()
                .checked_add(1)
                .ok_or(VulkanResidentFeedbackLoopRunnerError::FeedbackDepthOverflow)?;
            let feedback = VulkanResidentPrivateFeedbackSignal {
                id: format!("feedback_{}", self.feedback_counter),
                token_id: sampled_token_id,
                source_public_output_id: public.id.clone(),
                feedback_depth,
                closes_loop_after_processing: close_after_feedback,
                stop_reason: self
                    .last_stop_reason
                    .clone()
                    .filter(|_| close_after_feedback),
            };
            self.feedback_counter += 1;
            self.private_feedback_history.push(feedback.clone());

            let tick = VulkanResidentRunningStreamTick {
                stream_id: self.stream_id.clone(),
                stream_tick: Some(cycle_tick.stream_tick),
                status: VulkanResidentRunningStreamTickStatus::Processed,
                input_signal: Some(input),
                tick_run: Some(cycle_tick.tick_run),
                public_output: Some(public),
                private_feedback: Some(feedback.clone()),
                sampler_run: Some(run),
                stop_reason: self.last_stop_reason.clone(),
            };
            self.ticks.push(tick.clone());
            ticks.push(tick);

            if close_after_feedback && (!sampled_eos || tick_index + 1 == cycle_tick_count) {
                feedback_to_queue = Some(feedback);
                break;
            }
            input_signal = Some(VulkanResidentRunningStreamInputSignal::PrivateFeedback(
                feedback,
            ));
            if tick_index + 1 == cycle_tick_count {
                let VulkanResidentRunningStreamInputSignal::PrivateFeedback(feedback) =
                    input_signal.take().unwrap()
                else {
                    unreachable!("resident feedback cycle must end with private feedback")
                };
                feedback_to_queue = Some(feedback);
            }
        }

        if let Some(feedback) = feedback_to_queue {
            self.private_feedback_queue.push_back(feedback);
        }
        if let Some(tick_index) = restore_after_tick {
            self.processor
                .static_state_snapshots
                .restore_after_tick(&self.processor._mounted.buffers, tick_index)?;
        }
        Ok(ticks)
    }

    pub fn run_until_idle(
        &mut self,
        device: &VulkanComputeDevice,
    ) -> Result<Vec<VulkanResidentRunningStreamTick>, VulkanResidentFeedbackLoopRunnerError> {
        let start = self.ticks.len();
        while !self.external_input_queue.is_empty() || !self.private_feedback_queue.is_empty() {
            self.drive_backend_loop_window(device, self.processor.backend_loop_window)?;
        }
        self.tick(device)?;
        Ok(self.ticks[start..].to_vec())
    }

    pub fn run_prompt(
        &mut self,
        device: &VulkanComputeDevice,
        prompt_token_ids: &[u32],
        max_new_tokens: usize,
        eos_token_id: Option<u32>,
    ) -> Result<VulkanResidentRunningStreamRun, VulkanResidentFeedbackLoopRunnerError> {
        let start_public = self.public_outputs.len();
        let start_feedback = self.private_feedback_history.len();
        let start_stream_tick = self.next_stream_tick;
        self.inject_prompt(prompt_token_ids, max_new_tokens, eos_token_id)?;
        let ticks = self.run_until_idle(device)?;
        let public_outputs = self.public_outputs[start_public..].to_vec();
        let private_feedback = self.private_feedback_history[start_feedback..].to_vec();
        let generated_token_ids = public_outputs
            .iter()
            .map(|output| output.token_id)
            .collect::<Vec<_>>();
        let output_token_ids = prompt_token_ids
            .iter()
            .copied()
            .chain(generated_token_ids.iter().copied())
            .collect::<Vec<_>>();

        Ok(VulkanResidentRunningStreamRun {
            stream_id: self.stream_id.clone(),
            prompt_token_ids: prompt_token_ids.to_vec(),
            generated_token_ids,
            output_token_ids,
            stop_reason: self
                .last_stop_reason
                .clone()
                .unwrap_or_else(|| "max_new_tokens".to_string()),
            start_stream_tick,
            next_stream_tick: self.next_stream_tick,
            ticks,
            public_outputs,
            private_feedback,
        })
    }

    pub fn pending_external_input_count(&self) -> usize {
        self.external_input_queue.len()
    }

    pub fn pending_private_feedback_count(&self) -> usize {
        self.private_feedback_queue.len()
    }

    pub fn public_outputs(&self) -> &[VulkanResidentPublicOutputSignal] {
        &self.public_outputs
    }

    pub fn private_feedback_history(&self) -> &[VulkanResidentPrivateFeedbackSignal] {
        &self.private_feedback_history
    }

    pub fn ticks(&self) -> &[VulkanResidentRunningStreamTick] {
        &self.ticks
    }

    fn next_input_signal(&mut self) -> Option<VulkanResidentRunningStreamInputSignal> {
        if let Some(signal) = self.external_input_queue.pop_front() {
            return Some(VulkanResidentRunningStreamInputSignal::External(signal));
        }
        self.private_feedback_queue
            .pop_front()
            .map(VulkanResidentRunningStreamInputSignal::PrivateFeedback)
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentExternalInputSignal {
    pub id: String,
    pub token_id: u32,
    pub origin: String,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentPublicOutputSignal {
    pub id: String,
    pub token_id: u32,
    pub source_stream_tick: u64,
    pub sampler_run: VulkanResidentSamplerRun,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentPrivateFeedbackSignal {
    pub id: String,
    pub token_id: u32,
    pub source_public_output_id: String,
    pub feedback_depth: u32,
    pub closes_loop_after_processing: bool,
    pub stop_reason: Option<String>,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum VulkanResidentStreamControlEventType {
    Interrupt,
    StopAfterCurrent,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentStreamControlEvent {
    pub event_type: VulkanResidentStreamControlEventType,
    pub reason: String,
    pub cleared_private_feedback_ids: Vec<String>,
    pub closing_private_feedback_id: Option<String>,
    pub state_preserved: bool,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum VulkanResidentRunningStreamInputSignal {
    External(VulkanResidentExternalInputSignal),
    PrivateFeedback(VulkanResidentPrivateFeedbackSignal),
}

impl VulkanResidentRunningStreamInputSignal {
    pub fn token_id(&self) -> u32 {
        match self {
            Self::External(signal) => signal.token_id,
            Self::PrivateFeedback(signal) => signal.token_id,
        }
    }

    pub fn route(&self) -> VulkanResidentPromptEventInputRoute {
        match self {
            Self::External(_) => VulkanResidentPromptEventInputRoute::ExternalInput,
            Self::PrivateFeedback(_) => VulkanResidentPromptEventInputRoute::PrivateFeedback,
        }
    }

    pub fn feedback_depth(&self) -> u32 {
        match self {
            Self::External(_) => 0,
            Self::PrivateFeedback(signal) => signal.feedback_depth,
        }
    }

    pub fn closes_loop_after_processing(&self) -> bool {
        match self {
            Self::External(_) => false,
            Self::PrivateFeedback(signal) => signal.closes_loop_after_processing,
        }
    }

    pub fn stop_reason(&self) -> Option<&String> {
        match self {
            Self::External(_) => None,
            Self::PrivateFeedback(signal) => signal.stop_reason.as_ref(),
        }
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum VulkanResidentRunningStreamTickStatus {
    Processed,
    Idle,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentRunningStreamTick {
    pub stream_id: String,
    pub stream_tick: Option<u64>,
    pub status: VulkanResidentRunningStreamTickStatus,
    pub input_signal: Option<VulkanResidentRunningStreamInputSignal>,
    pub tick_run: Option<VulkanResidentSingleTokenTickRun>,
    pub public_output: Option<VulkanResidentPublicOutputSignal>,
    pub private_feedback: Option<VulkanResidentPrivateFeedbackSignal>,
    pub sampler_run: Option<VulkanResidentSamplerRun>,
    pub stop_reason: Option<String>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentRunningStreamRun {
    pub stream_id: String,
    pub prompt_token_ids: Vec<u32>,
    pub generated_token_ids: Vec<u32>,
    pub output_token_ids: Vec<u32>,
    pub stop_reason: String,
    pub start_stream_tick: u64,
    pub next_stream_tick: u64,
    pub ticks: Vec<VulkanResidentRunningStreamTick>,
    pub public_outputs: Vec<VulkanResidentPublicOutputSignal>,
    pub private_feedback: Vec<VulkanResidentPrivateFeedbackSignal>,
}

pub struct VulkanResidentTokenStream {
    inner: VulkanResidentRunningStream,
    current_input_event_id: Option<String>,
    current_output_index: usize,
}

impl VulkanResidentTokenStream {
    pub fn new(stream_id: impl Into<String>, processor: VulkanResidentStreamProcessor) -> Self {
        Self {
            inner: VulkanResidentRunningStream::new(stream_id, processor),
            current_input_event_id: None,
            current_output_index: 0,
        }
    }

    pub fn from_running_stream(stream: VulkanResidentRunningStream) -> Self {
        Self {
            inner: stream,
            current_input_event_id: None,
            current_output_index: 0,
        }
    }

    pub fn into_inner(self) -> VulkanResidentRunningStream {
        self.inner
    }

    pub fn stream_id(&self) -> &str {
        &self.inner.stream_id
    }

    pub fn next_stream_tick(&self) -> u64 {
        self.inner.next_stream_tick
    }

    pub fn submit_external_event(
        &mut self,
        device: &VulkanComputeDevice,
        event: VulkanResidentTokenInputEvent,
    ) -> Result<VulkanResidentTokenStreamRun, VulkanResidentFeedbackLoopRunnerError> {
        let start_stream_tick = self.inner.next_stream_tick;
        let queued = self.enqueue_external_event(event)?;
        let event = queued.input_event;
        let pump = self.pump_until_idle(device)?;

        let generated_token_ids = pump
            .output_events
            .iter()
            .map(|output| output.token_id)
            .collect::<Vec<_>>();

        Ok(VulkanResidentTokenStreamRun {
            stream_id: self.inner.stream_id.clone(),
            input_event: event,
            generated_token_ids,
            output_events: pump.output_events,
            stop_reason: self
                .inner
                .last_stop_reason
                .clone()
                .unwrap_or_else(|| "max_new_tokens".to_string()),
            start_stream_tick,
            next_stream_tick: self.inner.next_stream_tick,
            processed_tick_count: pump.processed_tick_count,
            idle_tick_count: pump.idle_tick_count,
        })
    }

    pub fn enqueue_external_event(
        &mut self,
        event: VulkanResidentTokenInputEvent,
    ) -> Result<VulkanResidentTokenQueuedInputEvent, VulkanResidentFeedbackLoopRunnerError> {
        let start_stream_tick = self.inner.next_stream_tick;
        let enqueued_token_count = event.token_ids.len();
        self.inner.inject_external_tokens_with_stop_tokens(
            &event.token_ids,
            event.max_public_tokens,
            event.stop_token_ids.clone(),
            event.origin.clone(),
        )?;
        self.current_input_event_id = Some(event.id.clone());
        self.current_output_index = 0;

        Ok(VulkanResidentTokenQueuedInputEvent {
            input_event: event,
            start_stream_tick,
            enqueued_token_count,
        })
    }

    pub fn pump_once(
        &mut self,
        device: &VulkanComputeDevice,
    ) -> Result<VulkanResidentTokenStreamTick, VulkanResidentFeedbackLoopRunnerError> {
        let tick = self.inner.tick(device)?;
        Ok(self.public_tick_from_running_tick(tick))
    }

    fn public_tick_from_running_tick(
        &mut self,
        tick: VulkanResidentRunningStreamTick,
    ) -> VulkanResidentTokenStreamTick {
        let output_event = tick.public_output.as_ref().map(|output| {
            let output_index = self.current_output_index;
            self.current_output_index += 1;
            VulkanResidentTokenOutputEvent {
                id: output.id.clone(),
                input_event_id: self
                    .current_input_event_id
                    .clone()
                    .unwrap_or_else(|| "feedback_loop".to_string()),
                output_index,
                token_id: output.token_id,
                source_stream_tick: output.source_stream_tick,
            }
        });

        VulkanResidentTokenStreamTick {
            stream_id: tick.stream_id,
            status: tick.status,
            stream_tick: tick.stream_tick,
            input_token_id: tick.input_signal.as_ref().map(|signal| signal.token_id()),
            input_route: tick.input_signal.as_ref().map(|signal| signal.route()),
            output_event,
            stop_reason: tick.stop_reason,
        }
    }

    pub fn pump_bounded(
        &mut self,
        device: &VulkanComputeDevice,
        max_ticks: usize,
    ) -> Result<VulkanResidentTokenStreamPumpRun, VulkanResidentFeedbackLoopRunnerError> {
        let start_stream_tick = self.inner.next_stream_tick;
        let mut ticks = Vec::new();
        let mut output_events = Vec::new();
        let mut processed_tick_count = 0usize;
        let mut idle_tick_count = 0usize;
        let mut stop_condition = VulkanResidentTokenStreamPumpStopCondition::TickBudget;

        while ticks.len() < max_ticks {
            let remaining_ticks = max_ticks - ticks.len();
            let running_ticks = self
                .inner
                .drive_backend_loop_window(device, remaining_ticks)?;
            let mut reached_idle = false;
            for running_tick in running_ticks {
                let tick = self.public_tick_from_running_tick(running_tick);
                match tick.status {
                    VulkanResidentRunningStreamTickStatus::Processed => {
                        processed_tick_count += 1;
                    }
                    VulkanResidentRunningStreamTickStatus::Idle => {
                        idle_tick_count += 1;
                        stop_condition = VulkanResidentTokenStreamPumpStopCondition::Idle;
                    }
                }
                if let Some(output_event) = tick.output_event.clone() {
                    output_events.push(output_event);
                }
                reached_idle = tick.status == VulkanResidentRunningStreamTickStatus::Idle;
                ticks.push(tick);
                if reached_idle || ticks.len() == max_ticks {
                    break;
                }
            }
            if reached_idle {
                break;
            }
        }

        Ok(VulkanResidentTokenStreamPumpRun {
            stream_id: self.inner.stream_id.clone(),
            start_stream_tick,
            next_stream_tick: self.inner.next_stream_tick,
            stop_condition,
            processed_tick_count,
            idle_tick_count,
            output_events,
            ticks,
            last_stop_reason: self.inner.last_stop_reason.clone(),
        })
    }

    pub fn pump_until_idle(
        &mut self,
        device: &VulkanComputeDevice,
    ) -> Result<VulkanResidentTokenStreamPumpRun, VulkanResidentFeedbackLoopRunnerError> {
        let start_stream_tick = self.inner.next_stream_tick;
        let mut ticks = Vec::new();
        let mut output_events = Vec::new();
        let mut processed_tick_count = 0usize;
        let mut idle_tick_count = 0usize;

        loop {
            let window = self.inner.processor.backend_loop_window;
            let run = self.pump_bounded(device, window)?;
            processed_tick_count += run.processed_tick_count;
            idle_tick_count += run.idle_tick_count;
            output_events.extend(run.output_events);
            ticks.extend(run.ticks);
            if run.stop_condition == VulkanResidentTokenStreamPumpStopCondition::Idle {
                break;
            }
        }

        Ok(VulkanResidentTokenStreamPumpRun {
            stream_id: self.inner.stream_id.clone(),
            start_stream_tick,
            next_stream_tick: self.inner.next_stream_tick,
            stop_condition: VulkanResidentTokenStreamPumpStopCondition::Idle,
            processed_tick_count,
            idle_tick_count,
            output_events,
            ticks,
            last_stop_reason: self.inner.last_stop_reason.clone(),
        })
    }

    pub fn interrupt(&mut self, reason: impl Into<String>) -> VulkanResidentStreamControlEvent {
        self.inner.interrupt(reason)
    }

    pub fn stop_after_current(
        &mut self,
        reason: impl Into<String>,
    ) -> VulkanResidentStreamControlEvent {
        self.inner.stop_after_current(reason)
    }

    pub fn snapshot(&self) -> VulkanResidentTokenStreamSnapshot {
        VulkanResidentTokenStreamSnapshot {
            stream_id: self.inner.stream_id.clone(),
            next_stream_tick: self.inner.next_stream_tick,
            loop_open: self.inner.loop_open,
            idle: self.inner.external_input_queue.is_empty()
                && self.inner.private_feedback_queue.is_empty(),
            total_public_outputs: self.inner.public_outputs.len(),
            total_ticks: self.inner.ticks.len(),
            last_stop_reason: self.inner.last_stop_reason.clone(),
        }
    }
}

