#[derive(Clone, Debug, PartialEq, Eq)]
pub struct VulkanResidentTokenModelPackageError {
    message: String,
}

impl VulkanResidentTokenModelPackageError {
    pub fn new(message: impl Into<String>) -> Self {
        Self {
            message: message.into(),
        }
    }
}

impl Display for VulkanResidentTokenModelPackageError {
    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        f.write_str(&self.message)
    }
}

impl Error for VulkanResidentTokenModelPackageError {}

#[derive(Clone, Debug, PartialEq, Serialize, Deserialize)]
pub struct VulkanResidentModelPackageManifest {
    pub schema: String,
    pub package_id: String,
    pub device_id: String,
    pub placement: StreamCircuitPlacementSpec,
    pub circuit_graph: VulkanResidentPackageCircuitGraph,
    pub tensor_index_path: String,
    pub behavioral_validation_path: String,
    pub config_path: String,
    pub tokenizer: VulkanResidentTokenizerPackageSpec,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub activation_element_bytes: Option<usize>,
    pub max_context_activations: usize,
    pub input_transducer: VulkanResidentInputEmbeddingTransducerPackageSpec,
    pub output_transducer: VulkanResidentOutputTransducerPackageSpec,
    pub sampler: VulkanResidentSamplerPackageSpec,
    pub pedal_executions: Vec<VulkanResidentPedalExecutionSpec>,
}

fn validate_behavioral_validation_artifact(
    manifest_path: &Path,
    relative_path: &str,
) -> io::Result<()> {
    if relative_path.is_empty() {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "resident model package does not declare behavioral validation evidence",
        ));
    }
    let path = manifest_path
        .parent()
        .unwrap_or_else(|| Path::new("."))
        .join(relative_path);
    let evidence: Value = serde_json::from_slice(&fs::read(&path)?).map_err(|error| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "invalid behavioral validation evidence {}: {error}",
                path.display()
            ),
        )
    })?;
    if evidence.get("schema").and_then(Value::as_str) != Some("llmoop.behavioral_validation.v1")
        || evidence.get("status").and_then(Value::as_str) != Some("passed")
    {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            format!(
                "behavioral validation evidence {} has not passed",
                path.display()
            ),
        ));
    }
    if evidence.get("candidate_kind").and_then(Value::as_str) != Some("exact_reference") {
        for mode in ["teacher_forced", "free_running"] {
            if evidence
                .get(mode)
                .and_then(|value| value.get("status"))
                .and_then(Value::as_str)
                != Some("passed")
            {
                return Err(io::Error::new(
                    io::ErrorKind::InvalidData,
                    format!(
                        "approximate candidate evidence {} lacks passing {mode} validation",
                        path.display()
                    ),
                ));
            }
        }
    }
    Ok(())
}

impl VulkanResidentModelPackageManifest {
    pub fn from_json_file(path: impl AsRef<Path>) -> io::Result<Self> {
        let path = path.as_ref();
        let bytes = fs::read(path)?;
        let manifest: Self = serde_json::from_slice(&bytes)
            .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
        if manifest.schema != VULKAN_RESIDENT_MODEL_PACKAGE_MANIFEST_SCHEMA {
            return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                format!(
                    "unsupported resident model package manifest schema {:?}",
                    manifest.schema
                ),
            ));
        }
        validate_behavioral_validation_artifact(path, &manifest.behavioral_validation_path)?;
        Ok(manifest)
    }

    pub fn write_json_file(&self, path: impl AsRef<Path>) -> io::Result<()> {
        let bytes = serde_json::to_vec_pretty(self)
            .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
        fs::write(path, bytes)
    }

    pub fn placement_device_ids(&self) -> Vec<String> {
        self.circuit_graph
            .pedals
            .iter()
            .map(|pedal| self.placement.device_for_pedal(&pedal.pedal_id).to_string())
            .collect::<BTreeSet<_>>()
            .into_iter()
            .collect()
    }

    pub fn with_runtime_placement(
        mut self,
        default_device_id: Option<&str>,
        pedal_devices: &BTreeMap<String, String>,
    ) -> Self {
        if let Some(default_device_id) = default_device_id {
            self.placement.default_device_id = default_device_id.to_string();
            self.device_id = default_device_id.to_string();
        }
        for (pedal_id, device_id) in pedal_devices {
            self.placement
                .pedal_devices
                .insert(pedal_id.clone(), device_id.clone());
        }
        self
    }

    pub fn with_runtime_patch_controls(
        self,
        default_device_id: Option<&str>,
        pedal_devices: &BTreeMap<String, String>,
        duplicate_after: &[(String, String)],
        source_chain: Option<&[(String, String)]>,
    ) -> Result<Self, VulkanResidentTokenModelPackageError> {
        if default_device_id.is_none()
            && pedal_devices.is_empty()
            && duplicate_after.is_empty()
            && source_chain.is_none()
        {
            return Ok(self);
        }

        let patch = self.runtime_patch_from_controls(
            default_device_id,
            pedal_devices,
            duplicate_after,
            source_chain,
        )?;

        self.with_runtime_patch(&patch)
    }

    pub fn runtime_patch_from_controls(
        &self,
        default_device_id: Option<&str>,
        pedal_devices: &BTreeMap<String, String>,
        duplicate_after: &[(String, String)],
        source_chain: Option<&[(String, String)]>,
    ) -> Result<StreamCircuitRuntimePatch, VulkanResidentTokenModelPackageError> {
        let source_graph = self
            .circuit_graph
            .to_resolved_lowered_pedalboard(PathBuf::from("."))?;
        let default_device_id = default_device_id
            .unwrap_or(&self.placement.default_device_id)
            .to_string();
        let mut patch = if let Some(source_chain) = source_chain {
            StreamCircuitRuntimePatch::from_source_chain(
                &source_graph,
                default_device_id,
                source_chain,
            )
        } else {
            StreamCircuitRuntimePatch::from_source_series(&source_graph, default_device_id)
        }
        .map_err(|error| VulkanResidentTokenModelPackageError::new(error.to_string()))?;

        for (pedal_id, device_id) in &self.placement.pedal_devices {
            if patch
                .instances
                .iter()
                .any(|instance| instance.instance_id == *pedal_id)
            {
                patch = patch
                    .with_instance_device(pedal_id, device_id)
                    .map_err(|error| {
                        VulkanResidentTokenModelPackageError::new(error.to_string())
                    })?;
            }
        }
        for (after_instance_id, new_instance_id) in duplicate_after {
            patch = patch
                .duplicate_after_instance(&source_graph, after_instance_id, new_instance_id)
                .map_err(|error| VulkanResidentTokenModelPackageError::new(error.to_string()))?;
        }
        for (instance_id, device_id) in pedal_devices {
            patch = patch
                .with_instance_device(instance_id, device_id)
                .map_err(|error| VulkanResidentTokenModelPackageError::new(error.to_string()))?;
        }

        Ok(patch)
    }

    pub fn resolved_source_graph(
        &self,
        package_root: impl Into<PathBuf>,
    ) -> Result<ResolvedLoweredPedalboard, VulkanResidentTokenModelPackageError> {
        self.circuit_graph
            .to_resolved_lowered_pedalboard(package_root)
    }

    pub fn with_runtime_patch(
        mut self,
        patch: &StreamCircuitRuntimePatch,
    ) -> Result<Self, VulkanResidentTokenModelPackageError> {
        let source_graph = self
            .circuit_graph
            .to_resolved_lowered_pedalboard(PathBuf::from("."))?;
        patch
            .validate_against_graph(&source_graph)
            .map_err(|error| VulkanResidentTokenModelPackageError::new(error.to_string()))?;

        let source_pedals = self
            .circuit_graph
            .pedals
            .iter()
            .map(|pedal| (pedal.pedal_id.as_str(), pedal))
            .collect::<BTreeMap<_, _>>();
        let source_executions = self
            .pedal_executions
            .iter()
            .map(|execution| (execution.pedal_id.as_str(), execution))
            .collect::<BTreeMap<_, _>>();

        let ordered_instance_ids = patch
            .topological_instance_ids(&source_graph)
            .map_err(|error| VulkanResidentTokenModelPackageError::new(error.to_string()))?;
        let enabled_instance_count = ordered_instance_ids.len();
        let mut pedals = Vec::with_capacity(enabled_instance_count);
        let mut pedal_executions = Vec::with_capacity(enabled_instance_count);
        let mut placement = StreamCircuitPlacementSpec::new(patch.default_device_id.clone());

        for instance_id in ordered_instance_ids {
            let instance = patch
                .instances
                .iter()
                .find(|instance| instance.instance_id == instance_id)
                .expect("validated topological instance id must exist");
            let source_pedal = source_pedals
                .get(instance.source_pedal_id.as_str())
                .ok_or_else(|| {
                    VulkanResidentTokenModelPackageError::new(format!(
                        "runtime patch instance {} references unknown source pedal {}",
                        instance.instance_id, instance.source_pedal_id
                    ))
                })?;
            let mut pedal = (*source_pedal).clone();
            pedal.pedal_id = instance.instance_id.clone();
            pedal.circuit.source.pedal_id = instance.instance_id.clone();
            apply_runtime_patch_state_policy(&mut pedal, patch, instance);
            pedals.push(pedal);

            let source_execution = source_executions
                .get(instance.source_pedal_id.as_str())
                .ok_or_else(|| {
                    VulkanResidentTokenModelPackageError::new(format!(
                        "runtime patch source pedal {} has no execution spec",
                        instance.source_pedal_id
                    ))
                })?;
            let mut execution = (*source_execution).clone();
            execution.pedal_id = instance.instance_id.clone();
            pedal_executions.push(execution);

            if instance.device_id != patch.default_device_id {
                placement = placement.with_pedal_device(&instance.instance_id, &instance.device_id);
            }
        }

        self.device_id = patch.default_device_id.clone();
        self.placement = placement;
        self.circuit_graph.wiring = patch.wiring.clone();
        self.circuit_graph.cables = patch
            .effective_cables()
            .map_err(|error| VulkanResidentTokenModelPackageError::new(error.to_string()))?;
        self.circuit_graph.pedals = pedals;
        self.pedal_executions = pedal_executions;
        Ok(self)
    }
}

fn apply_runtime_patch_state_policy(
    pedal: &mut VulkanResidentPackagePedalCircuit,
    patch: &StreamCircuitRuntimePatch,
    instance: &crate::stream_circuit::StreamCircuitPedalInstance,
) {
    let (mode, mut source_instance_id) = match &instance.state_policy {
        StreamCircuitPedalInstanceStatePolicy::Fresh => return,
        StreamCircuitPedalInstanceStatePolicy::CloneFrom { instance_id } => {
            ("clone_from", instance_id.as_str())
        }
        StreamCircuitPedalInstanceStatePolicy::ShareWith { instance_id } => {
            ("shared_from", instance_id.as_str())
        }
    };
    if mode == "clone_from" {
        loop {
            let source = patch
                .instances
                .iter()
                .find(|candidate| candidate.instance_id == source_instance_id)
                .expect("validated state source instance must exist");
            match &source.state_policy {
                StreamCircuitPedalInstanceStatePolicy::ShareWith { instance_id } => {
                    source_instance_id = instance_id;
                }
                StreamCircuitPedalInstanceStatePolicy::Fresh
                | StreamCircuitPedalInstanceStatePolicy::CloneFrom { .. } => break,
            }
        }
    }
    let source_prefix = format!("{mode}:{source_instance_id}.");
    for state in &mut pedal.state.state_ports {
        state.sharing = Some(format!("{source_prefix}{}", state.id));
    }
    for state in &mut pedal.circuit.state_ports {
        state.sharing = Some(format!("{source_prefix}{}", state.id));
    }
}

#[derive(Clone, Debug, PartialEq, Serialize, Deserialize)]
pub struct VulkanResidentPackageCircuitGraph {
    pub wiring: String,
    pub cables: Vec<crate::stream_circuit::StreamCircuitGraphCable>,
    #[serde(default)]
    pub architecture: Value,
    #[serde(default)]
    pub dimensions: Value,
    #[serde(default)]
    pub input_transducer: Value,
    #[serde(default)]
    pub output_transducer: Value,
    #[serde(default)]
    pub pedals: Vec<VulkanResidentPackagePedalCircuit>,
}

impl VulkanResidentPackageCircuitGraph {
    fn to_resolved_lowered_pedalboard(
        &self,
        package_root: impl Into<PathBuf>,
    ) -> Result<ResolvedLoweredPedalboard, VulkanResidentTokenModelPackageError> {
        let mut operator_counts = BTreeMap::new();
        let mut circuit_refs = Vec::with_capacity(self.pedals.len());
        let mut circuits = Vec::with_capacity(self.pedals.len());

        for pedal in &self.pedals {
            *operator_counts
                .entry(pedal.operator_type.clone())
                .or_insert(0) += 1;
            let circuit_ref = LoweredCircuitRef {
                id: pedal.pedal_id.clone(),
                operator_type: pedal.operator_type.clone(),
                circuit: format!("package://{}/circuit", pedal.pedal_id),
                params: format!("package://{}/params", pedal.pedal_id),
                state: format!("package://{}/state", pedal.pedal_id),
                implementation: pedal.implementation.clone(),
                behavioral_role: pedal.behavioral_role.clone(),
            };
            let resolved = ResolvedCircuitArtifact {
                pedal: circuit_ref.clone(),
                circuit: pedal.circuit.clone(),
                params: pedal.params.clone(),
                state: pedal.state.clone(),
            };
            resolved.validate().map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "resident package circuit graph pedal {} is invalid: {error}",
                    pedal.pedal_id
                ))
            })?;
            circuit_refs.push(circuit_ref);
            circuits.push(resolved);
        }

        let index = LoweredPedalboard {
            schema: LOWERED_PEDALBOARD_SCHEMA.to_string(),
            source: LoweredPedalboardSource {
                format: VULKAN_RESIDENT_MODEL_PACKAGE_MANIFEST_SCHEMA.to_string(),
                artifact_root: "package".to_string(),
            },
            architecture: self.architecture.clone(),
            dimensions: self.dimensions.clone(),
            graph: LoweredPedalboardGraph {
                wiring: self.wiring.clone(),
                circuits: circuit_refs,
                cables: self.cables.clone(),
                input_transducer: self.input_transducer.clone(),
                output_transducer: self.output_transducer.clone(),
            },
            summary: LoweredPedalboardSummary {
                circuit_count: self.pedals.len(),
                operator_counts,
            },
            notes: vec!["resolved from resident model package manifest".to_string()],
        };
        index.validate_index().map_err(|error| {
            VulkanResidentTokenModelPackageError::new(format!(
                "resident package circuit graph is invalid: {error}"
            ))
        })?;

        Ok(ResolvedLoweredPedalboard {
            artifact_root: package_root.into(),
            index,
            circuits,
        })
    }
}

