impl VulkanResidentModelPackage {
    pub fn from_manifest_file(
        device: &VulkanComputeDevice,
        manifest_path: impl AsRef<Path>,
    ) -> Result<Self, VulkanResidentTokenModelPackageError> {
        Self::from_manifest_file_with_capacity(device, manifest_path, None)
    }

    pub fn from_manifest_file_with_capacity(
        device: &VulkanComputeDevice,
        manifest_path: impl AsRef<Path>,
        dynamic_state_capacity_activations: Option<usize>,
    ) -> Result<Self, VulkanResidentTokenModelPackageError> {
        let manifest_path = manifest_path.as_ref();
        let manifest =
            VulkanResidentModelPackageManifest::from_json_file(manifest_path).map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to load resident model package manifest {:?}: {error}",
                    manifest_path
                ))
            })?;
        let manifest_dir = manifest_path
            .parent()
            .map(Path::to_path_buf)
            .unwrap_or_else(|| PathBuf::from("."));
        Self::from_manifest(
            device,
            &manifest_dir,
            manifest,
            dynamic_state_capacity_activations,
        )
    }

    pub fn from_manifest(
        device: &VulkanComputeDevice,
        manifest_dir: impl AsRef<Path>,
        manifest: VulkanResidentModelPackageManifest,
        dynamic_state_capacity_activations: Option<usize>,
    ) -> Result<Self, VulkanResidentTokenModelPackageError> {
        let manifest_dir = manifest_dir.as_ref();
        let capacity =
            dynamic_state_capacity_activations.unwrap_or(manifest.max_context_activations);
        if capacity == 0 {
            return Err(VulkanResidentTokenModelPackageError::new(
                "resident dynamic state capacity must be at least 1 activation",
            ));
        }
        validate_pedal_executions(&manifest)?;

        let tensor_index_path =
            resolve_resident_model_package_path(manifest_dir, &manifest.tensor_index_path);
        let (tensor_index, resource_plan, placed_plan) =
            plan_resident_package_single_device_stream_circuit(
                &manifest.device_id,
                &manifest.placement,
                &manifest.circuit_graph,
                manifest_dir,
                &tensor_index_path,
                manifest.activation_element_bytes,
            )?;
        let parameter_buffer_plan = VulkanPermanentParameterBufferPlan::from_placed_resident_plan(
            &placed_plan.placed_resident_plan,
        )
        .map_err(|error| {
            VulkanResidentTokenModelPackageError::new(format!(
                "failed to create resident parameter buffer plan: {error}"
            ))
        })?;
        let parameter_buffers = Arc::new(parameter_buffer_plan.allocate_buffers(device).map_err(
            |error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to allocate resident parameter buffers: {error}"
                ))
            },
        )?);
        parameter_buffers
            .load_from_tensor_index(&tensor_index)
            .map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to load resident model parameters: {error}"
                ))
            })?;

        let transducer_parameter_buffers =
            Arc::new(load_resident_package_transducer_parameter_buffers(
                device,
                &manifest.device_id,
                &resource_plan,
                &tensor_index,
            )?);
        let input_transducer_spirv_words = load_required_resident_model_package_shader(
            manifest_dir,
            &manifest.input_transducer.shader_path,
        )?;
        let embedding_norm_spirv_words = load_required_resident_model_package_shader(
            manifest_dir,
            &manifest.output_transducer.embedding_norm_shader_path,
        )?;
        let tied_projection_spirv_words = load_required_resident_model_package_shader(
            manifest_dir,
            &manifest.output_transducer.projection_shader_path,
        )?;
        let sampler_spirv_words = load_required_resident_model_package_shader(
            manifest_dir,
            &manifest.sampler.shader_path,
        )?;

        let probe_mounted =
            VulkanMountedPlacedStreamCircuit::from_placed_plan_with_parameter_buffers(
                device,
                placed_plan.clone(),
                capacity,
                parameter_buffers.clone(),
            )
            .map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to mount Vulkan stream circuit for shared model binding: {error}"
                ))
            })?;
        let reusable_manifest =
            resident_package_reusable_kernel_manifest(&probe_mounted.placed_plan);
        let mounted_bound = probe_mounted
            .mounted_placed_bound_dispatch_plan(&reusable_manifest)
            .map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to bind Vulkan stream circuit dispatch plan: {error}"
                ))
            })?;
        validate_pedal_executions_against_mounted_dispatches(&manifest, &mounted_bound)?;
        let pedal_kernel_shaders = resident_package_pedal_kernel_shader_refs(&manifest);
        let loaded_manifest = loaded_kernel_pack_from_package_shader_refs(
            manifest_dir,
            &probe_mounted,
            &mounted_bound,
            &pedal_kernel_shaders,
        )?;

        Ok(Self {
            package_id: manifest.package_id,
            device_id: manifest.device_id,
            dynamic_state_capacity_activations: capacity,
            permanent_parameter_count: parameter_buffers.plan.parameter_count,
            permanent_parameter_bytes: parameter_buffers.total_byte_capacity,
            transducer_parameter_count: transducer_parameter_buffers.plan.parameter_count,
            transducer_parameter_bytes: transducer_parameter_buffers.total_byte_capacity,
            reusable_kernel_word_count: loaded_manifest.total_word_count,
            placed_plan,
            mounted_bound,
            loaded_manifest,
            parameter_buffers,
            transducer_parameter_buffers,
            input_transducer_spirv_words,
            embedding_norm_spirv_words,
            tied_projection_spirv_words,
            sampler_spirv_words,
            input_transducer_spec: manifest.input_transducer.spec,
            output_transducer_spec: manifest.output_transducer.spec,
            sampler_spec: manifest.sampler.spec,
        })
    }

    pub fn create_stream_processor(
        &self,
        device: &VulkanComputeDevice,
    ) -> Result<VulkanResidentStreamProcessor, VulkanResidentTokenModelPackageError> {
        let mounted = VulkanMountedPlacedStreamCircuit::from_placed_plan_with_parameter_buffers(
            device,
            self.placed_plan.clone(),
            self.dynamic_state_capacity_activations,
            self.parameter_buffers.clone(),
        )
        .map_err(|error| {
            VulkanResidentTokenModelPackageError::new(format!(
                "failed to mount Vulkan stream circuit for stream instance: {error}"
            ))
        })?;
        mounted.buffers.zero_state_buffers().map_err(|error| {
            VulkanResidentTokenModelPackageError::new(format!(
                "failed to zero stream state buffers: {error}"
            ))
        })?;
        mounted
            .buffers
            .apply_clone_state_policies()
            .map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to initialize cloned stream state: {error}"
                ))
            })?;
        let pedal_ids = self
            .placed_plan
            .placed_resident_plan
            .hosted_pedal_ids
            .clone();
        let input_transducer =
            VulkanResidentInputEmbeddingTransducerRunner::from_mounted_token_embedding(
                device,
                &mounted,
                &self.transducer_parameter_buffers,
                &self.input_transducer_spirv_words,
                &self.input_transducer_spec,
            )
            .map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to create input token embedding transducer: {error}"
                ))
            })?;
        let pedalboard = mounted
            .create_resident_pedalboard_runner(
                device,
                &self.mounted_bound,
                pedal_ids.iter().map(String::as_str),
                &self.loaded_manifest,
            )
            .map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to create resident pedalboard runner: {error}"
                ))
            })?;
        let output_transducer =
            VulkanResidentOutputTransducerRunner::from_mounted_output_transducer(
                device,
                &mounted,
                &self.transducer_parameter_buffers,
                &self.embedding_norm_spirv_words,
                &self.tied_projection_spirv_words,
                &self.output_transducer_spec,
            )
            .map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to create output transducer: {error}"
                ))
            })?;
        let sampler = VulkanResidentSamplerRunner::from_output_transducer_with_spec(
            device,
            &mounted,
            &output_transducer,
            &self.sampler_spirv_words,
            &self.sampler_spec,
        )
        .map_err(|error| {
            VulkanResidentTokenModelPackageError::new(format!(
                "failed to create sampler pedal: {error}"
            ))
        })?;
        let tick_runner = VulkanResidentSingleTokenTickRunner::new(
            device,
            input_transducer,
            pedalboard,
            output_transducer,
        )
        .map_err(|error| {
            VulkanResidentTokenModelPackageError::new(format!(
                "failed to create single-token tick runner: {error}"
            ))
        })?;
        let loop_runner =
            VulkanResidentFeedbackLoopRunner::new(tick_runner, sampler).map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to create feedback loop runner: {error}"
                ))
            })?;

        VulkanResidentStreamProcessor::new(
            device,
            mounted,
            self.transducer_parameter_buffers.clone(),
            loop_runner,
        )
        .map_err(|error| {
            VulkanResidentTokenModelPackageError::new(format!(
                "failed to create resident feedback snapshot bank: {error}"
            ))
        })
    }
}

impl VulkanResidentTokenModelPackage for VulkanResidentModelPackage {
    fn device_id(&self) -> &str {
        &self.device_id
    }

    fn dynamic_state_capacity_activations(&self) -> usize {
        self.dynamic_state_capacity_activations
    }

    fn permanent_parameter_count(&self) -> usize {
        self.permanent_parameter_count
    }

    fn permanent_parameter_bytes(&self) -> usize {
        self.permanent_parameter_bytes
    }

    fn transducer_parameter_count(&self) -> usize {
        self.transducer_parameter_count
    }

    fn transducer_parameter_bytes(&self) -> usize {
        self.transducer_parameter_bytes
    }

    fn reusable_kernel_word_count(&self) -> usize {
        self.reusable_kernel_word_count
    }

    fn create_stream_processor(
        &self,
        device: &VulkanComputeDevice,
    ) -> Result<VulkanResidentStreamProcessor, VulkanResidentTokenModelPackageError> {
        VulkanResidentModelPackage::create_stream_processor(self, device)
    }
}

fn validate_pedal_executions(
    manifest: &VulkanResidentModelPackageManifest,
) -> Result<(), VulkanResidentTokenModelPackageError> {
    if manifest.pedal_executions.is_empty() {
        return Err(VulkanResidentTokenModelPackageError::new(format!(
            "resident model package {:?} does not declare pedal executions",
            manifest.package_id
        )));
    }
    let mut declared_kernels = BTreeSet::new();
    for pedal in &manifest.pedal_executions {
        if pedal.kernels.is_empty() {
            return Err(VulkanResidentTokenModelPackageError::new(format!(
                "resident model package {:?} declares pedal {:?} with no executable kernels",
                manifest.package_id, pedal.pedal_id
            )));
        }
        for kernel in &pedal.kernels {
            if !declared_kernels.insert((pedal.pedal_id.as_str(), kernel.node_id.as_str())) {
                return Err(VulkanResidentTokenModelPackageError::new(format!(
                    "resident model package {:?} declares duplicate pedal kernel {}.{}",
                    manifest.package_id, pedal.pedal_id, kernel.node_id
                )));
            }
        }
    }

    Ok(())
}

fn validate_pedal_executions_against_mounted_dispatches(
    manifest: &VulkanResidentModelPackageManifest,
    mounted_bound: &VulkanMountedPlacedBoundDispatchPlan,
) -> Result<(), VulkanResidentTokenModelPackageError> {
    let declared_pedals = manifest
        .pedal_executions
        .iter()
        .map(|pedal| pedal.pedal_id.as_str())
        .collect::<BTreeSet<_>>();
    let mounted_pedals = mounted_bound
        .dispatches
        .iter()
        .map(|dispatch| dispatch.pedal_id.as_str())
        .collect::<BTreeSet<_>>();

    let missing_pedals = mounted_pedals
        .difference(&declared_pedals)
        .copied()
        .collect::<Vec<_>>();
    if !missing_pedals.is_empty() {
        return Err(VulkanResidentTokenModelPackageError::new(format!(
            "resident model package {:?} is missing pedal executions for mounted pedals: {}",
            manifest.package_id,
            missing_pedals.join(", ")
        )));
    }

    let unknown_pedals = declared_pedals
        .difference(&mounted_pedals)
        .copied()
        .collect::<Vec<_>>();
    if !unknown_pedals.is_empty() {
        return Err(VulkanResidentTokenModelPackageError::new(format!(
            "resident model package {:?} declares pedal executions for unknown mounted pedals: {}",
            manifest.package_id,
            unknown_pedals.join(", ")
        )));
    }

    for pedal in &manifest.pedal_executions {
        let mounted_dispatches = mounted_bound
            .dispatches
            .iter()
            .filter(|dispatch| dispatch.pedal_id == pedal.pedal_id)
            .collect::<Vec<_>>();
        if pedal.kernels.len() != mounted_dispatches.len() {
            return Err(VulkanResidentTokenModelPackageError::new(format!(
                "resident model package {:?} declares {} kernels for pedal {}, but mounted dispatch plan has {}",
                manifest.package_id,
                pedal.kernels.len(),
                pedal.pedal_id,
                mounted_dispatches.len()
            )));
        }

        for (expected_index, (kernel, dispatch)) in
            pedal.kernels.iter().zip(mounted_dispatches).enumerate()
        {
            if kernel.execution_index != expected_index {
                return Err(VulkanResidentTokenModelPackageError::new(format!(
                    "resident model package {:?} declares pedal {} kernel {} with execution_index {}, expected {}",
                    manifest.package_id,
                    pedal.pedal_id,
                    kernel.node_id,
                    kernel.execution_index,
                    expected_index
                )));
            }
            if kernel.node_id != dispatch.node_id {
                return Err(VulkanResidentTokenModelPackageError::new(format!(
                    "resident model package {:?} declares pedal {} execution_index {} as node {}, but mounted dispatch plan has node {}",
                    manifest.package_id,
                    pedal.pedal_id,
                    expected_index,
                    kernel.node_id,
                    dispatch.node_id
                )));
            }
            if kernel.op != dispatch.op {
                return Err(VulkanResidentTokenModelPackageError::new(format!(
                    "resident model package {:?} declares pedal {} node {} op {}, but mounted dispatch plan has op {}",
                    manifest.package_id, pedal.pedal_id, kernel.node_id, kernel.op, dispatch.op
                )));
            }
            if kernel.execution_index != dispatch.node_index {
                return Err(VulkanResidentTokenModelPackageError::new(format!(
                    "resident model package {:?} declares pedal {} node {} execution_index {}, but mounted dispatch plan has node_index {}",
                    manifest.package_id,
                    pedal.pedal_id,
                    kernel.node_id,
                    kernel.execution_index,
                    dispatch.node_index
                )));
            }
        }
    }

    Ok(())
}

fn validate_pedal_executions_cover_mounted_dispatches(
    manifest: &VulkanResidentModelPackageManifest,
    mounted_bound: &VulkanMountedPlacedBoundDispatchPlan,
) -> Result<(), VulkanResidentTokenModelPackageError> {
    let declared_pedals = manifest
        .pedal_executions
        .iter()
        .map(|pedal| pedal.pedal_id.as_str())
        .collect::<BTreeSet<_>>();
    let mounted_pedals = mounted_bound
        .dispatches
        .iter()
        .map(|dispatch| dispatch.pedal_id.as_str())
        .collect::<BTreeSet<_>>();

    let missing_pedals = mounted_pedals
        .difference(&declared_pedals)
        .copied()
        .collect::<Vec<_>>();
    if !missing_pedals.is_empty() {
        return Err(VulkanResidentTokenModelPackageError::new(format!(
            "resident model package {:?} is missing pedal executions for mounted pedals: {}",
            manifest.package_id,
            missing_pedals.join(", ")
        )));
    }

    for pedal in manifest
        .pedal_executions
        .iter()
        .filter(|pedal| mounted_pedals.contains(pedal.pedal_id.as_str()))
    {
        let mounted_dispatches = mounted_bound
            .dispatches
            .iter()
            .filter(|dispatch| dispatch.pedal_id == pedal.pedal_id)
            .collect::<Vec<_>>();
        if pedal.kernels.len() != mounted_dispatches.len() {
            return Err(VulkanResidentTokenModelPackageError::new(format!(
                "resident model package {:?} declares {} kernels for mounted pedal {}, but mounted dispatch plan has {}",
                manifest.package_id,
                pedal.kernels.len(),
                pedal.pedal_id,
                mounted_dispatches.len()
            )));
        }

        for (expected_index, (kernel, dispatch)) in
            pedal.kernels.iter().zip(mounted_dispatches).enumerate()
        {
            if kernel.execution_index != expected_index {
                return Err(VulkanResidentTokenModelPackageError::new(format!(
                    "resident model package {:?} declares pedal {} kernel {} with execution_index {}, expected {}",
                    manifest.package_id,
                    pedal.pedal_id,
                    kernel.node_id,
                    kernel.execution_index,
                    expected_index
                )));
            }
            if kernel.node_id != dispatch.node_id {
                return Err(VulkanResidentTokenModelPackageError::new(format!(
                    "resident model package {:?} declares mounted pedal {} execution_index {} as node {}, but mounted dispatch plan has node {}",
                    manifest.package_id,
                    pedal.pedal_id,
                    expected_index,
                    kernel.node_id,
                    dispatch.node_id
                )));
            }
            if kernel.op != dispatch.op {
                return Err(VulkanResidentTokenModelPackageError::new(format!(
                    "resident model package {:?} declares mounted pedal {} node {} op {}, but mounted dispatch plan has op {}",
                    manifest.package_id, pedal.pedal_id, kernel.node_id, kernel.op, dispatch.op
                )));
            }
            if kernel.execution_index != dispatch.node_index {
                return Err(VulkanResidentTokenModelPackageError::new(format!(
                    "resident model package {:?} declares mounted pedal {} node {} execution_index {}, but mounted dispatch plan has node_index {}",
                    manifest.package_id,
                    pedal.pedal_id,
                    kernel.node_id,
                    kernel.execution_index,
                    dispatch.node_index
                )));
            }
        }
    }

    Ok(())
}

fn resolve_resident_model_package_path(manifest_dir: &Path, path: &str) -> PathBuf {
    let path = Path::new(path);
    if path.is_absolute() {
        path.to_path_buf()
    } else {
        manifest_dir.join(path)
    }
}

fn plan_resident_package_single_device_stream_circuit(
    device_id: &str,
    placement_spec: &StreamCircuitPlacementSpec,
    circuit_graph: &VulkanResidentPackageCircuitGraph,
    manifest_dir: &Path,
    tensor_index_path: &Path,
    activation_element_bytes: Option<usize>,
) -> Result<
    (
        TensorIndex,
        StreamCircuitResourcePlan,
        VulkanPlacedStreamCircuitPlan,
    ),
    VulkanResidentTokenModelPackageError,
> {
    let (tensor_index, resource_plan, placement_plan, placed_plan) =
        plan_resident_package_placed_stream_circuit(
            device_id,
            placement_spec,
            circuit_graph,
            manifest_dir,
            tensor_index_path,
            activation_element_bytes,
        )?;
    validate_single_device_resident_package_placement(device_id, &placement_plan)?;
    Ok((tensor_index, resource_plan, placed_plan))
}

fn plan_resident_package_placed_stream_circuit(
    device_id: &str,
    placement_spec: &StreamCircuitPlacementSpec,
    circuit_graph: &VulkanResidentPackageCircuitGraph,
    manifest_dir: &Path,
    tensor_index_path: &Path,
    activation_element_bytes: Option<usize>,
) -> Result<
    (
        TensorIndex,
        StreamCircuitResourcePlan,
        StreamCircuitPlacementPlan,
        VulkanPlacedStreamCircuitPlan,
    ),
    VulkanResidentTokenModelPackageError,
> {
    let graph = circuit_graph.to_resolved_lowered_pedalboard(manifest_dir.to_path_buf())?;
    let tensor_index = TensorIndex::from_json_file(tensor_index_path).map_err(|error| {
        VulkanResidentTokenModelPackageError::new(format!(
            "failed to load tensor index {:?}: {error}",
            tensor_index_path
        ))
    })?;
    let execution_plan =
        StreamCircuitExecutionPlan::from_graph_with_tensor_index(&graph, &tensor_index).map_err(
            |error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to create stream execution plan: {error}"
                ))
            },
        )?;
    let resource_plan = StreamCircuitResourcePlan::from_graph_and_plan(&graph, &execution_plan)
        .map_err(|error| {
            VulkanResidentTokenModelPackageError::new(format!(
                "failed to create stream resource plan: {error}"
            ))
        })?;
    let placement_plan = graph.placement_plan(placement_spec).map_err(|error| {
        VulkanResidentTokenModelPackageError::new(format!(
            "failed to create placement plan for {device_id:?}: {error}"
        ))
    })?;
    let resident = VulkanPlacedStreamCircuitResidentPlan::from_resource_plan_for_device(
        &resource_plan,
        &placement_plan,
        device_id,
        Some(&tensor_index),
        activation_element_bytes,
    )
    .map_err(|error| {
        VulkanResidentTokenModelPackageError::new(format!(
            "failed to create Vulkan resident plan for {device_id:?}: {error}"
        ))
    })?;
    let placed_plan =
        VulkanPlacedStreamCircuitPlan::from_plans(&execution_plan, &resource_plan, resident)
            .map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to create Vulkan placed stream circuit plan: {error}"
                ))
            })?;
    Ok((tensor_index, resource_plan, placement_plan, placed_plan))
}

fn validate_single_device_resident_package_placement(
    device_id: &str,
    placement_plan: &StreamCircuitPlacementPlan,
) -> Result<(), VulkanResidentTokenModelPackageError> {
    let remote_pedals = placement_plan
        .pedals
        .iter()
        .filter(|pedal| pedal.device_id != device_id)
        .map(|pedal| format!("{}@{}", pedal.pedal_id, pedal.device_id))
        .collect::<Vec<_>>();
    if !remote_pedals.is_empty() {
        return Err(VulkanResidentTokenModelPackageError::new(format!(
            "single-device resident package for {device_id:?} cannot host remote pedals: {}",
            remote_pedals.join(", ")
        )));
    }
    if placement_plan.cross_device_cable_count != 0 {
        return Err(VulkanResidentTokenModelPackageError::new(format!(
            "single-device resident package for {device_id:?} cannot host {} cross-device cables",
            placement_plan.cross_device_cable_count
        )));
    }
    Ok(())
}

fn load_resident_package_transducer_parameter_buffers(
    device: &VulkanComputeDevice,
    device_id: &str,
    resource_plan: &StreamCircuitResourcePlan,
    tensor_index: &TensorIndex,
) -> Result<VulkanPermanentParameterBuffers, VulkanResidentTokenModelPackageError> {
    let transducer_parameter_plan = VulkanPermanentParameterBufferPlan::from_transducer_parameters(
        device_id,
        resource_plan,
        Some(tensor_index),
    )
    .map_err(|error| {
        VulkanResidentTokenModelPackageError::new(format!(
            "failed to create transducer parameter plan: {error}"
        ))
    })?;
    let transducer_parameter_buffers =
        transducer_parameter_plan
            .allocate_buffers(device)
            .map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to allocate transducer parameter buffers: {error}"
                ))
            })?;
    transducer_parameter_buffers
        .load_from_tensor_index(tensor_index)
        .map_err(|error| {
            VulkanResidentTokenModelPackageError::new(format!(
                "failed to load transducer parameters: {error}"
            ))
        })?;
    Ok(transducer_parameter_buffers)
}

fn load_resident_package_transducer_parameter_buffers_for(
    device: &VulkanComputeDevice,
    device_id: &str,
    resource_plan: &StreamCircuitResourcePlan,
    tensor_index: &TensorIndex,
    transducer_id: &str,
) -> Result<VulkanPermanentParameterBuffers, VulkanResidentTokenModelPackageError> {
    let transducer_parameter_plan =
        VulkanPermanentParameterBufferPlan::from_transducer_parameters_for(
            device_id,
            resource_plan,
            Some(tensor_index),
            transducer_id,
        )
        .map_err(|error| {
            VulkanResidentTokenModelPackageError::new(format!(
                "failed to create {transducer_id} parameter plan: {error}"
            ))
        })?;
    let transducer_parameter_buffers =
        transducer_parameter_plan
            .allocate_buffers(device)
            .map_err(|error| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "failed to allocate {transducer_id} parameter buffers: {error}"
                ))
            })?;
    transducer_parameter_buffers
        .load_from_tensor_index(tensor_index)
        .map_err(|error| {
            VulkanResidentTokenModelPackageError::new(format!(
                "failed to load {transducer_id} parameters: {error}"
            ))
        })?;
    Ok(transducer_parameter_buffers)
}

fn resident_package_reusable_kernel_manifest(
    placed_plan: &VulkanPlacedStreamCircuitPlan,
) -> VulkanReusableKernelArtifactManifest {
    VulkanReusableKernelArtifactManifest::new(
        placed_plan
            .reusable_kernel_plan
            .families
            .iter()
            .map(|family| {
                VulkanReusableKernelArtifact::from_family(
                    family,
                    format!("kernels/{}.spv", family.family_id),
                )
            })
            .collect(),
    )
}

fn resident_package_pedal_kernel_shader_refs(
    manifest: &VulkanResidentModelPackageManifest,
) -> Vec<VulkanResidentPedalKernelShaderRef> {
    manifest
        .pedal_executions
        .iter()
        .flat_map(|pedal| {
            pedal
                .kernels
                .iter()
                .map(|kernel| VulkanResidentPedalKernelShaderRef {
                    pedal_id: pedal.pedal_id.clone(),
                    node_id: kernel.node_id.clone(),
                    shader_path: kernel.shader_path.clone(),
                    local_size_x: kernel.local_size_x,
                    workgroup_count_x: kernel.workgroup_count_x,
                })
        })
        .collect()
}

fn resident_package_pedal_kernel_shader_refs_for_mounted_dispatches(
    manifest: &VulkanResidentModelPackageManifest,
    mounted_bound: &VulkanMountedPlacedBoundDispatchPlan,
) -> Vec<VulkanResidentPedalKernelShaderRef> {
    resident_package_pedal_kernel_shader_refs(manifest)
        .into_iter()
        .filter(|shader| {
            mounted_bound
                .dispatch(&shader.pedal_id, &shader.node_id)
                .is_some()
        })
        .collect()
}

fn loaded_kernel_pack_from_package_shader_refs(
    manifest_dir: &Path,
    mounted: &VulkanMountedPlacedStreamCircuit,
    mounted_bound: &VulkanMountedPlacedBoundDispatchPlan,
    dispatch_shaders: &[VulkanResidentPedalKernelShaderRef],
) -> Result<VulkanLoadedReusableKernelArtifactManifest, VulkanResidentTokenModelPackageError> {
    let mut loaded_artifacts = Vec::new();
    let mut loaded_families = BTreeSet::new();
    let mut total_word_count = 0usize;

    for shader in dispatch_shaders {
        let dispatch = mounted_bound
            .dispatch(&shader.pedal_id, &shader.node_id)
            .ok_or_else(|| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "mounted dispatch {}.{} declared by resident model package is missing",
                    shader.pedal_id, shader.node_id
                ))
            })?;
        if !loaded_families.insert(dispatch.reusable_family_id.clone()) {
            continue;
        }
        let spirv_words =
            load_required_resident_model_package_shader(manifest_dir, &shader.shader_path)?;
        total_word_count = total_word_count
            .checked_add(spirv_words.len())
            .ok_or_else(|| {
                VulkanResidentTokenModelPackageError::new(
                    "reusable kernel artifact word count overflowed",
                )
            })?;
        let family = mounted
            .placed_plan
            .reusable_kernel_plan
            .family(&dispatch.reusable_family_id)
            .ok_or_else(|| {
                VulkanResidentTokenModelPackageError::new(format!(
                    "reusable kernel family {:?} declared by mounted dispatch {}.{} is missing",
                    dispatch.reusable_family_id, shader.pedal_id, shader.node_id
                ))
            })?;
        loaded_artifacts.push(VulkanLoadedReusableKernelArtifact {
            artifact: VulkanReusableKernelArtifact::from_family(family, shader.shader_path.clone())
                .with_local_size_x(shader.local_size_x)
                .with_workgroup_count_x(shader.workgroup_count_x),
            resolved_path: resolve_resident_model_package_path(manifest_dir, &shader.shader_path),
            words: spirv_words,
        });
    }

    let required_families: BTreeSet<&str> = mounted
        .placed_plan
        .reusable_kernel_plan
        .families
        .iter()
        .map(|family| family.family_id.as_str())
        .collect();
    let loaded_family_ids: BTreeSet<&str> = loaded_artifacts
        .iter()
        .map(|artifact| artifact.artifact.family_id.as_str())
        .collect();
    let missing_families = required_families
        .difference(&loaded_family_ids)
        .copied()
        .collect::<Vec<_>>();
    if !missing_families.is_empty() {
        return Err(VulkanResidentTokenModelPackageError::new(format!(
            "resident model package is missing shaders for reusable kernel families: {}",
            missing_families.join(", ")
        )));
    }

    Ok(VulkanLoadedReusableKernelArtifactManifest {
        schema: VULKAN_REUSABLE_KERNEL_ARTIFACT_MANIFEST_SCHEMA.to_string(),
        backend_id: VULKAN_STREAM_CIRCUIT_BACKEND_ID.to_string(),
        artifacts: loaded_artifacts,
        total_word_count,
    })
}

fn load_required_resident_model_package_shader(
    manifest_dir: &Path,
    shader_path: &str,
) -> Result<Vec<u32>, VulkanResidentTokenModelPackageError> {
    let resolved_path = resolve_resident_model_package_path(manifest_dir, shader_path);
    if resolved_path
        .extension()
        .and_then(|extension| extension.to_str())
        != Some("spv")
    {
        return Err(VulkanResidentTokenModelPackageError::new(format!(
            "resident model package shader {:?} is not a compiled SPIR-V artifact",
            resolved_path
        )));
    }
    read_spirv_words(&resolved_path).map_err(|error| {
        VulkanResidentTokenModelPackageError::new(format!(
            "failed to load compiled Vulkan shader {:?}: {error}",
            resolved_path
        ))
    })
}

