    #[test]
    fn runtime_placement_overrides_package_manifest_in_memory() {
        let manifest = fixture_model_package_manifest();
        assert_eq!(manifest.placement.default_device_id, "runtime_default");
        assert!(manifest.placement.pedal_devices.is_empty());

        let mut pedal_devices = BTreeMap::new();
        pedal_devices.insert("layer_02".to_string(), "gpu1".to_string());
        let split = manifest
            .clone()
            .with_runtime_placement(None, &pedal_devices);

        assert!(manifest.placement.pedal_devices.is_empty());
        assert_eq!(split.device_id, "runtime_default");
        assert_eq!(
            split.placement.device_for_pedal("layer_00"),
            "runtime_default"
        );
        assert_eq!(split.placement.device_for_pedal("layer_02"), "gpu1");
        assert_eq!(
            split.placement_device_ids(),
            vec!["gpu1", "runtime_default"]
        );

        let moved = manifest.with_runtime_placement(Some("gpu1"), &BTreeMap::new());
        assert_eq!(moved.device_id, "gpu1");
        assert_eq!(moved.placement.default_device_id, "gpu1");
        assert_eq!(moved.placement_device_ids(), vec!["gpu1"]);
    }

    #[test]
    fn runtime_patch_duplicates_package_pedals_in_memory() {
        let manifest = fixture_model_package_manifest();
        let source_graph = manifest
            .circuit_graph
            .to_resolved_lowered_pedalboard(PathBuf::from("."))
            .unwrap();
        let patch = StreamCircuitRuntimePatch::from_source_series(&source_graph, "gpu0")
            .unwrap()
            .duplicate_after_instance(&source_graph, "layer_05", "layer_05_repeat")
            .unwrap()
            .with_instance_device("layer_05_repeat", "gpu1")
            .unwrap();

        let patched = manifest.clone().with_runtime_patch(&patch).unwrap();

        assert_eq!(manifest.circuit_graph.pedals.len(), 14);
        assert_eq!(manifest.pedal_executions.len(), 14);
        assert!(
            manifest
                .circuit_graph
                .pedals
                .iter()
                .all(|pedal| pedal.pedal_id != "layer_05_repeat")
        );

        assert_eq!(patched.circuit_graph.pedals.len(), 15);
        assert_eq!(patched.pedal_executions.len(), 15);
        assert_eq!(
            patched.placement.device_for_pedal("layer_05_repeat"),
            "gpu1"
        );
        let repeated_pedal = patched
            .circuit_graph
            .pedals
            .iter()
            .find(|pedal| pedal.pedal_id == "layer_05_repeat")
            .unwrap();
        let source_pedal = manifest
            .circuit_graph
            .pedals
            .iter()
            .find(|pedal| pedal.pedal_id == "layer_05")
            .unwrap();
        assert_eq!(repeated_pedal.operator_type, source_pedal.operator_type);
        assert_eq!(repeated_pedal.circuit.id, source_pedal.circuit.id);
        assert_eq!(repeated_pedal.circuit.source.pedal_id, "layer_05_repeat");
        assert_eq!(
            repeated_pedal.params.refs.keys().collect::<Vec<_>>(),
            source_pedal.params.refs.keys().collect::<Vec<_>>()
        );

        let repeated_execution = patched
            .pedal_executions
            .iter()
            .find(|execution| execution.pedal_id == "layer_05_repeat")
            .unwrap();
        let source_execution = manifest
            .pedal_executions
            .iter()
            .find(|execution| execution.pedal_id == "layer_05")
            .unwrap();
        assert_eq!(repeated_execution.kernels, source_execution.kernels);
    }

    #[test]
    fn runtime_patch_state_policies_change_resident_state_allocation_and_binding() {
        let manifest = fixture_model_package_manifest();
        let source_graph = manifest
            .circuit_graph
            .to_resolved_lowered_pedalboard(PathBuf::from("."))
            .unwrap();
        let state_id = source_graph
            .circuits
            .iter()
            .find(|artifact| artifact.pedal.id == "layer_05")
            .and_then(|artifact| artifact.state.state_ports.first())
            .map(|state| state.id.clone())
            .unwrap();
        let mut shared_patch = StreamCircuitRuntimePatch::from_source_series(&source_graph, "gpu0")
            .unwrap()
            .duplicate_after_instance(&source_graph, "layer_05", "layer_05_repeat")
            .unwrap();
        shared_patch
            .instances
            .iter_mut()
            .find(|instance| instance.instance_id == "layer_05_repeat")
            .unwrap()
            .state_policy = StreamCircuitPedalInstanceStatePolicy::ShareWith {
            instance_id: "layer_05".to_string(),
        };
        let shared_manifest = manifest.clone().with_runtime_patch(&shared_patch).unwrap();
        let shared_graph = shared_manifest
            .circuit_graph
            .to_resolved_lowered_pedalboard(PathBuf::from("."))
            .unwrap();
        let shared_execution = StreamCircuitExecutionPlan::from_graph(&shared_graph).unwrap();
        let shared_resources =
            StreamCircuitResourcePlan::from_graph_and_plan(&shared_graph, &shared_execution)
                .unwrap();
        let shared_resident =
            VulkanStreamCircuitResidentPlan::from_resource_plan(&shared_resources, None, Some(2))
                .unwrap();

        assert_eq!(shared_resident.stream_state_buffers.len(), 14);
        let shared_bindings = state_binding_index(&shared_resources, &shared_resident).unwrap();
        assert_eq!(
            shared_bindings
                .get(&("layer_05_repeat".to_string(), state_id.clone()))
                .unwrap()
                .pedal_id,
            "layer_05"
        );

        let mut cloned_patch = shared_patch;
        cloned_patch
            .instances
            .iter_mut()
            .find(|instance| instance.instance_id == "layer_05_repeat")
            .unwrap()
            .state_policy = StreamCircuitPedalInstanceStatePolicy::CloneFrom {
            instance_id: "layer_05".to_string(),
        };
        let cloned_manifest = manifest.with_runtime_patch(&cloned_patch).unwrap();
        let cloned_graph = cloned_manifest
            .circuit_graph
            .to_resolved_lowered_pedalboard(PathBuf::from("."))
            .unwrap();
        let cloned_execution = StreamCircuitExecutionPlan::from_graph(&cloned_graph).unwrap();
        let cloned_resources =
            StreamCircuitResourcePlan::from_graph_and_plan(&cloned_graph, &cloned_execution)
                .unwrap();
        let cloned_resident =
            VulkanStreamCircuitResidentPlan::from_resource_plan(&cloned_resources, None, Some(2))
                .unwrap();
        let cloned = cloned_resident
            .stream_state_buffers
            .iter()
            .find(|state| state.pedal_id == "layer_05_repeat" && state.state_id == state_id)
            .unwrap();
        assert_eq!(cloned.clone_from, Some(("layer_05".to_string(), state_id)));
        assert_eq!(cloned_resident.stream_state_buffers.len(), 15);
    }

